import { defined } from "../../../../utils/zcutils";

const KEY = 'axisline'; //domain
export function radial_domain_position(data) {
    const position = this.helpers.position;
    position[KEY] = {};

    //* define variables here
    const { renderer, commonOption } = this,
        { orient, tickConstants, tickSizeOuter, tickmarkStart, range0, range1 } = commonOption,
        { k, h } = tickConstants;

    position[KEY].path = (function path(d, encode) {
        return orient === 'left' || orient == 'right'
            ? `M${k * (tickSizeOuter + tickmarkStart)},${range0}${h}0.5V${range1}H${k * (tickSizeOuter + tickmarkStart)}`
            : `M${range0},${k * tickSizeOuter}V0.5H${range1}V${k * tickSizeOuter}`
    })();
}

